options.customCss:
:root {
    /* Tipografia: Transição para Inter/System-UI para maior legibilidade */
    --font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
    --font-weight-normal: 400;
    --font-weight-bold: 700;
    --font-size-body: 14px;
    --font-size-label: 15px;
    --font-size-input: 16px; /* Aumento para evitar zoom automático em dispositivos móveis */
    --font-size-header: 32px;
    --font-size-paragraph: 16px;
    --font-size-subheader: 18px;

    /* Colors: Paleta baseada em Slate e Indigo (SaaS Premium) */
    --color-background: #f8fafc; /* Um cinza azulado muito leve para profundidade */
    --color-card-bg: #ffffff;
    --color-card-border: rgba(226, 232, 240, 0.8);
    --color-card-shadow: rgba(15, 23, 42, 0.08);
    --color-header: #0f172a; /* Azul quase preto para autoridade visual */
    --color-label: #334155;
    --color-input-border: #cbd5e1;
    --color-input-text: #1e293b;
    --color-focus-border: #6366f1; /* Indigo vibrante para feedback ativo */
    --color-submit-btn-bg: #4f46e5;
    --color-submit-btn-text: #ffffff;
    --color-required: #ef4444;

    /* Border Radii: Suavização das arestas (Apple-style) */
    --border-radius-card: 20px;
    --border-radius-input: 12px;

    /* Spacing: Aplicação de respiro visual (Negative Space) */
    --padding-container-top: 60px;
    --padding-card: 48px;
    --margin-bottom-card: 32px;
    --padding-form-input: 14px;

    /* Dimensions */
    --container-width: 520px; /* Alargamento sutil para conforto visual */
    --submit-btn-height: 56px;

    /* Outros: Sombra multicamada para realismo tátil */
    --box-shadow-card: 0 10px 15px -3px var(--color-card-shadow), 0 4px 6px -4px var(--color-card-shadow);
}

/* Injeção da Identidade Visual (Logo) no topo do Formulário */
.n8n-form-card::before {
    content: '';
    display: block;
    width: 100%;
    height: 100px;
    background: url('https://drive.google.com/uc?export=view&id=10-IkFzMdrcyNcVGOf-GkCWpNmklgCWlG') center no-repeat;
    background-size: contain;
    margin-bottom: 30px;
}

/* Efeito de Microinteração no Botão de Envio */
button[type="submit"] {
    transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1) !important;
    box-shadow: 0 4px 6px -1px rgba(79, 70, 229, 0.3) !important;
    text-transform: none !important;
    letter-spacing: -0.01em !important;
}

button[type="submit"]:hover {
    filter: brightness(1.1) !important;
    transform: translateY(-2px) !important;
    box-shadow: 0 10px 15px -3px rgba(79, 70, 229, 0.4) !important;
}

/* Refinamento dos Campos de Texto */
input, textarea {
    border: 1.5px solid var(--color-input-border) !important;
    transition: border-color 0.2s ease, box-shadow 0.2s ease !important;
}

input:focus {
    box-shadow: 0 0 0 4px rgba(99, 102, 241, 0.15) !important;
}

